ot; data-darkreader-inline-color=&quot;&quot;&gt; 9 &lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;है&lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;, &lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;जबकि&lt;/span&gt; &lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;आकृति&lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt; 3 &lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;में&lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;, &lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;आकृति&lt;/span&gt; &lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;के&lt;/span&gt; &lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;अंदर&lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt; 10 &lt;/span&gt;&lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;वर्ग&lt;/span&gt; &lt;span data-darkreader-inline-bgcolor=&quot;&quot; data-darkreader-inline-bgimage=&quot;&quot; data-darkreader-inline-color=&quot;&quot;&gt;हैं।&lt;/span&gt;&lt;/p&gt;
